fn simple_loop(n: i32) -> i32 {
    let mut sum = 0;
    for i in 0..n {
        sum = sum + i;
    }
    return sum;
}

fn tensor_add(a: Tensor<f32>, b: Tensor<f32>) -> Tensor<f32> {
    return a + b;
}

fn matrix_multiply(a: Tensor<f32>, b: Tensor<f32>) -> Tensor<f32> {
    let m = a.shape()[0];
    let n = a.shape()[1];
    let p = b.shape()[1];
    let mut result = Tensor::zeros([m, p]);

    for i in 0..m {
        for j in 0..p {
            for k in 0..n {
                result[i][j] += a[i][k] * b[k][j];
            }
        }
    }
    return result;
}

async fn parallel_map<T, U>(items: Vec<T>, f: fn(T) -> U) -> Vec<U> {
    let tasks = items.map(|item| spawn(async { f(item) }));
    return await join_all(tasks);
}

@constant_time
fn secure_compare(a: &[u8], b: &[u8]) -> bool {
    if a.len() != b.len() {
        return false;
    }
    let mut result = 0u8;
    for i in 0..a.len() {
        result |= a[i] ^ b[i];
    }
    return result == 0;
}

fn unrolled_sum(arr: &[i32; 8]) -> i32 {
    let mut sum = 0;
    for i in 0..8 {
        sum += arr[i];
    }
    return sum;
}

fn simd_vector_add(a: &[f32], b: &[f32], result: &mut [f32]) {
    for i in 0..a.len() {
        result[i] = a[i] + b[i];
    }
}
